import { NextResponse } from 'next/server';
import { mkdir, writeFile } from 'fs/promises';
import path from 'path';
import { prisma } from '@/lib/prisma';
import { requireCompanyProfileAdmin } from '@/lib/companyProfileAccess';

const ALLOWED = new Set(['image/jpeg', 'image/png', 'image/webp', 'image/gif']);
const MAX_BYTES = 5 * 1024 * 1024;

export async function POST(req: Request) {
  const gate = await requireCompanyProfileAdmin(req);
  if ('error' in gate) return gate.error;

  const formData = await req.formData().catch(() => null);
  if (!formData) {
    return NextResponse.json({ error: 'Invalid form data' }, { status: 400 });
  }

  const file = formData.get('file');
  if (!file || !(file instanceof File)) {
    return NextResponse.json({ error: 'Missing file' }, { status: 400 });
  }

  if (!ALLOWED.has(file.type)) {
    return NextResponse.json({ error: 'Only JPEG, PNG, WebP, or GIF images are allowed' }, { status: 400 });
  }

  const buf = Buffer.from(await file.arrayBuffer());
  if (buf.length > MAX_BYTES) {
    return NextResponse.json({ error: 'File too large (max 5MB)' }, { status: 400 });
  }

  const ext =
    file.type === 'image/png'
      ? 'png'
      : file.type === 'image/webp'
        ? 'webp'
        : file.type === 'image/gif'
          ? 'gif'
          : 'jpg';
  const safeName = `${Date.now()}-${Math.random().toString(36).slice(2, 10)}.${ext}`;
  const dir = path.join(process.cwd(), 'public', 'uploads', 'company');
  await mkdir(dir, { recursive: true });
  const fsPath = path.join(dir, safeName);
  await writeFile(fsPath, buf);

  const publicUrl = `/uploads/company/${safeName}`;

  const media = await prisma.media.create({
    data: {
      filename: safeName,
      mimeType: file.type,
      size: buf.length,
      folder: 'company',
      url: publicUrl,
      uploadedById: gate.user.id,
    },
    select: { id: true, url: true },
  });

  return NextResponse.json({ ok: true, url: media.url, mediaId: media.id });
}
